var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"제법이군. 더 덤벼 보겠느냐?","JPN":"やるのう。もっと続けるか？","ENG":"Impressive. Ready for more?","TWN":"不錯，還要再來嗎？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크으으……</b>","JPN":"<b>グルル……</b>","ENG":"<b>Khhhkkk...</b>","TWN":"<b>咳呃呃……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"흐음, 시시하긴.","JPN":"ふん、つまらぬのう。","ENG":"Hmm. Underwhelming.","TWN":"哼，真無聊。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"벌써 지쳤느냐? 날 잡아먹겠다고 기세등등할 때는 언제고.","JPN":"もう疲れたのか？　妾を食い殺すと意気込んでいたくせに？","ENG":"Tired already? I thought you were eager to devour me.","TWN":"已經累了嗎？剛才不是還一副凶神惡煞地想要吃掉我？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이름이……. 아, 그래. 레비아탄이라고 했지.","JPN":"名が……そうそう。レヴィアタンと言っておったな。","ENG":"What was your name... Oh, right. Leviathan.","TWN":"名字……啊，對了，叫利維坦對吧。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"자아, 어서 일어나서 덤벼 보아라.","JPN":"さあ、立ってもう一度かかってきてみろ。","ENG":"Now, stand up and face me again.","TWN":"好了，快站起來，繼續吧。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내 친히 네가 누비던 <color=#ffd34c>바다</color>에까지 와 주지 않았느냐.","JPN":"其方が最も動きやすい<color=#ffd34c>海</color>までわざわざ来てやったではないか。","ENG":"I came all the way to the <color=#ffd34c>ocean</color>that you dearly love.","TWN":"我不是親自來到你生活的<color=#ffd34c>大海</color>了嗎。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"신을 물어뜯겠다고 했던가? 이 정도에 꺾일 거였으면 이빨을 드러내지 말았어야지.","JPN":"神を嚙み千切るのではなかったか？　この程度で戦意喪失するくらいなら最初から牙を向けるでない。","ENG":"Biting and tearing down a god? You shouldn’t have shown your teeth if this was everything you had.","TWN":"不是說要吞掉神嗎？這種程度就被打倒的話，一開始就不該露出獠牙。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크륵……. 큭…….</b>","JPN":"<b>グルル……グル……</b>","ENG":"<b>Krrr... Krgh...</b>","TWN":"<b>呃唔……呃……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크흐흐흐…….</b>","JPN":"<b>クフフフ……</b>","ENG":"<b>Ke he he he he...</b>","TWN":"<b>咳呵呵呵……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음? 뭐가 그리 우습지?","JPN":"ふむ？　何が面白いのじゃ？","ENG":"Hmm? What’s so funny?","TWN":"嗯？什麼事那麼好笑？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크흐, 흐으……. 그야 우습고 말고.</b>","JPN":"<b>くふ、ふう……そりゃ面白いさ。</b>","ENG":"<b>Ke he, he... Of course, it's funny.</b>","TWN":"<b>咳呵……當然好笑了。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>마지막 사냥이……. 하필이면 사냥꾼을 사냥감으로 착각한 꼴이었다니.</b>","JPN":"<b>最後の狩りが……まさか狙った獲物に逆に狩られる気分だったなんて。</b>","ENG":"<b>The irony of mistaking a predator for a prey... On my last hunt.</b>","TWN":"<b>最後的狩獵……把獵人錯當成了獵物。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐응, 재밌군.","JPN":"ふむ、面白いのう。","ENG":"Hmm, interesting.","TWN":"唔，有意思。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"골이 비었어도 마왕이란 것이, 그리 쉽게 패배를 인정하기라도 할 셈인가?","JPN":"いくら骨抜きだろうと、魔王は魔王。そう簡単に敗北を認めてもいいのか？","ENG":"Foolish as you sound, you are still a Demon Lord. Are you going to accept your defeat that easily?","TWN":"就算腦袋空空，你也算是個魔王，那麼輕易就想認輸了嗎？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아니면 날 방심시키기라도 하려고?","JPN":"それとも妾を油断させる作戦か？","ENG":"Or are you just trying to lower my guard?","TWN":"還是說想讓我掉以輕心？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하긴, 짐승인 네게 품격 따위를 바라는 것도 과하겠지만.","JPN":"まぁ、獣である其方に品格など望むべくもないが。","ENG":"To be fair, there's only so much I could ask of a mere beast.","TWN":"但實話說，期望身為畜生的你具備品格什麼的，是我要求過分了。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>이제까지 성공한 사냥들은 기억에 남지 않았어.</b>","JPN":"<b>これまで成功した狩りは、あまり記憶にも残っていない。</b>","ENG":"<b>I do not recall any of the successful hunts.</b>","TWN":"<b>雖然我的腦海中沒有成功狩獵的記憶。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>하지만 오늘의 실패는……. 정말이지 각별하군.</b>","JPN":"<b>でも今日の失敗は……なんとも格別でな。</b>","ENG":"<b>But today's failure... It is truly something else.</b>","TWN":"<b>但今天的失敗……真的很特別。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"호오. 보기보단 변명이 장황하구나.","JPN":"ほお。意外とくどくどと言い訳を言う奴だったのじゃな。","ENG":"Ah. What an extravagant excuse.","TWN":"吼？狡辯之言真是冗長啊。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>안타까워, 아스모데우스. 정말이지 안타까워……. </b>","JPN":"<b>残念だ、アスモデウス。本当に残念だ……</b>","ENG":"<b>Such a shame, Asmodeus. A shame indeed...</b>","TWN":"<b>太可惜了，阿斯蒙蒂斯，真的太可惜了……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>그 대단한 불꽃을 누구에게 휘두를 수 있지?</b>","JPN":"<b>あの凄まじい炎を、受け止められる相手はいるの？</b>","ENG":"<b>Who can you properly wield those flames against?</b>","TWN":"<b>你那了不起的火焰還能夠揮向誰呢？</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>온 세상을 불사르기에 마땅한 그 불꽃이, 대체 언제쯤 마음껏 날뛸 수 있을까?</b>","JPN":"<b>世界中を燃やし尽くせるほどのその炎は、いったいいつになったら思う存分暴れられるんだろうね？</b>","ENG":"<b>Your flames, powerful enough to burn down the whole world... When will it ever be able to dance freely?</b>","TWN":"<b>那足以焚滅整個世界的火焰，究竟什麼時候才能盡情地跳動呢？</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>전력을 다했는데 이길 수 없었다…….</b>","JPN":"<b>全力を出しても、勝てなかった……</b>","ENG":"<b>I tried everything in my power... but I could not win.</b>","TWN":"<b>用盡了全力也無法戰勝……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>다시 한 번 싸우고 싶은 이 기분을……! 적을 능가하고 싶다는 고양감을……!</b>","JPN":"<b>もう一度戦ってみたいと思うこの気持ちを……！　敵を超えたいという高揚感を……！</b>","ENG":"<b>The desire to fight once more...! The sensation of wanting to surpass your enemy...!</b>","TWN":"<b>想要再次戰鬥的這種心情……！想要超越敵人的激情……！</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>다음에는 반드시 사냥에 성공하고 말겠다는 열망을……!</b>","JPN":"<b>次こそ必ず狩ってやるという熱望を……！</b>","ENG":"<b>The longing to succeed the next hunt...!</b>","TWN":"<b>下次狩獵必須成功的渴望……！</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>이 후련한 기분을…… 너는 영원히 느낄 수도, 이해할 수도 없을 거다.</b>","JPN":"<b>この清々しい気持ちを……お前は永遠に感じることも、理解することもできない。</b>","ENG":"<b>You will never be able to feel... this bliss of a feeling.</b>","TWN":"<b>這種暢快的心情……你永遠體會不到，也永遠理解不了。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>최강의 마왕이니까.</b>","JPN":"<b>最強の魔王だから。</b>","ENG":"<b>Because you are the greatest Demon Lord of all.</b>","TWN":"<b>因為你是最強的魔王。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"단순해 빠진 짐승 주제에 흥이 깨지는 소리를 지껄이는군.","JPN":"思考が単純な獣の分際で、興覚めなことを言ってくれるものじゃ。","ENG":"You talk too much trash for a lowlife beast.","TWN":"掃興。身為一個畜生你話太多了。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"너에게 남은 마지막 시간으로 날 불쾌하게 만들 작정이었다면, 칭찬해 주지.","JPN":"残された最後の時間で妾を不快にさせようとしたのなら、褒めてやろう。","ENG":"If your goal was to make me feel uncomfortable, you’ve succeeded.","TWN":"如果你打算用最後僅剩的時間讓我感到不快的話，那我要稱讚你。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크흐…… 흐흐흐흐……</b>","JPN":"<b>くふ……ふふふふ……</b>","ENG":"<b>Ke he... Ke he he...</b>","TWN":"<b>咳呵……呵呵呵呵……</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>사냥꾼의 심장은 사냥감이 있을 때 뛰는 법이지.</b>","JPN":"<b>狩人の心臓は獲物を前にした時に弾むというもの。</b>","ENG":"<b>A hunter's heart only beats when there is prey to catch.</b>","TWN":"<b>獵人的心臟在有獵物的時候才會跳動。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>적수가 없는 영생이란, 정말 비극이야.</b>","JPN":"<b>敵のいない永遠の命なんて、悲劇そのもの。</b>","ENG":"<b>What a tragic life it is. A life of unrivaled immortality...</b>","TWN":"<b>沒有對手的永生，才是真正的悲劇。</b>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……정말 재미있지 않아, 힐데?","JPN":"……本当に興味深くないか、ヒルデ？","ENG":"...Isn’t it funny, Hilde?","TWN":"……你不覺得很有意思嗎，希爾德？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그 단순해 빠진 짐승 놈이, 마지막에 가서야 맞는 말을 지껄이다니.","JPN":"あの単純な脳細胞の獣が、最後の最後では正しいことを吐くとはのう。","ENG":"That lowlife beast was actually right, in its last moment.","TWN":"那個頭腦簡單的畜生，至少說對了一句話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"힘을 개방한 것만으로도 공간이 증발하기 시작했네요.","JPN":"力を解放しただけで、空間が消滅しはじめましたね。","ENG":"The space around us is evaporating, just from unleashing her powers.","TWN":"只是釋放力量，空間就開始蒸發了呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정말이지…. 경이로운 출력이에요.","JPN":"本当に…なんという驚異的な出力でしょう。","ENG":"What magnificent power, if I do say so myself...","TWN":"的確……是令人驚歎的輸出。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 아아아……!","JPN":"あ、あああ……！","ENG":"Ah, Aaaah...!","TWN":"啊，啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 열기다……. 평생을 갈구해 온 극상의 고통……!","JPN":"あの熱気よ……今までずっとあれほど求め続けてきた極上の苦しみ……！","ENG":"It's the heat... The ultimate pain I've been craving for, all these years...!","TWN":"那股熱情……是我一生渴求的終極痛苦……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"어서, 어서 나에게 그 고통을 느끼게 해 다오.","JPN":"早く、早く私に苦しみを味わせておくれ。","ENG":"Hurry, let me feel the pain.","TWN":"給我！快，快點讓我感受那種痛苦！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"오감이 망가지고 신경의 말단이 타들어가기 전에……! 자아, 어서……!","JPN":"五感が機能しなくなり、神経の末端まで燃え落ちる前に……！　さぁ、早く……！","ENG":"Before my senses die and my nerves burn to ashes...! Quickly, now...!","TWN":"在我五感壞掉，神經末端燃燒之前……！來，快點……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"큭, 하아…… 아……?","JPN":"くっ、はぁ……あ……？","ENG":"Kgh, Haah... Ah...?","TWN":"咳，哈啊……啊……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L11_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아무것도 느껴지지 않아. 허리가 잘렸는데…… 어째서……","JPN":"何も感じない。腰を切断されたというのに……どうしてなの……","ENG":"My waist has been severed... But I don’t feel a thing... Why...?","TWN":"我的腰，被砍斷了？……為什麼……我什麼都感覺不到？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 어째서……! 어째서어어……!!","JPN":"ああっ、どうしてっ……！　どうしてぇぇ……！！","ENG":"Aaah, why...! Why...!","TWN":"啊啊，為什麼……！為什麼……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"호오, 재미있는 반응인걸.","JPN":"ほお、面白い反応じゃのう。","ENG":"Oh, a rather interesting response.","TWN":"喔？這個反應有點意思。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네 그 연약한 몸뚱아리 따위가 고통을 느낄 겨를이 있을 줄 알았느냐?","JPN":"其方のその軟弱な身体が痛みを感じる余裕なぞ、あると思ったか？","ENG":"Did you think your weak fragile body was durable enough to feel the pain?","TWN":"就憑你那副孱弱的軀體，還有閒工夫去感受什麼痛苦？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"뭐라……!","JPN":"なにっ……！","ENG":"What...!","TWN":"什麼……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"모르는 모양이니 내가 친절함이라는 걸 발휘해서 설명해 주마.","JPN":"知らないようじゃから、親切心から教えてやろう。","ENG":"Since you have no idea where this is getting at, I shall kindly explain.","TWN":"看你好像不太明白，那我就親切地為你解釋一下。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자고로 고통이라는 건, 공격을 받고도 버틸 수 있을 때 느껴지는 거란다.","JPN":"苦痛というものはの、耐えられる攻撃に対してのみ感じるものなのじゃ。","ENG":"One can only feel pain when their body is capable of withstanding the attack.","TWN":"自古以來，痛苦，就是在受到攻擊後還能堅持下來時才會感受到的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"이해되느냐? 잡종 꼬마야.","JPN":"理解したか？　雑種のガキ。","ENG":"Understood? Mongrel child.","TWN":"明白了嗎，你這個混種狐狸？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"안 돼……. 이래서는 안 돼……","JPN":"ダメよ……これではダメ……","ENG":"No... This isn’t how it's supposed to be...","TWN":"不，不……不應該是這樣的……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"탐식자……! 처음부터 이렇게 될 거라고 예상했구나……!","JPN":"貪食者……！　最初からこうなると知っていたのね……！","ENG":"Devourer...! You knew this was going to happen...!","TWN":"貪食者……！你從一開始就預料到會變成這樣嗎……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……글쎄요. 저희 계획도 반은 실패, 반은 성공이라고 해야겠는데요.","JPN":"……さあ。我々の計画も半分は失敗で、半分は成功のようです。","ENG":"...Well, it seems like our plan has succeeded only halfway.","TWN":"……怎麼說呢。應該說我們的計畫一半失敗，一半成功了吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희가 아는 아스모데우스 님의 화력이라면 당신이 충분히 버틸 거라고 계산했지만……","JPN":"我々の知るアスモデウス様の火力なら、あなたでも十分耐えられると思いましたが……","ENG":"We assumed you would be able to hold up against Asmodeus's power that we knew of...","TWN":"如果是我們所了解的阿斯蒙蒂斯，你應該能撐得住……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"오히려 더 강해지셨어요.","JPN":"むしろ前より強くなっていましたね。","ENG":"...But she became stronger.","TWN":"但是她比以前更強了呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"나는 늑대가 어떤 결정을 내릴지 지켜보기 위해 여기 온 거란다.","JPN":"妾は狼が下す決断を見届けるために、ここに来たのじゃ。","ENG":"I am here to watch what decision the Wolf makes.","TWN":"我來這裡，只是想看看狼究竟會做出怎樣的決定。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그리고 내 감상을 방해하는 것들은 누구 하나 용납할 생각 없느니라.","JPN":"そして妾の鑑賞を邪魔する奴は、誰であろうと許すつもりはない。","ENG":"And I will show no mercy to those who are in my way.","TWN":"敢妨礙我看好戲的傢伙，我一個都不會容忍。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그래야 관리자 녀석도 이렇게까지 일을 키운 보람이 있지 않겠느냐?","JPN":"それでこそ、管理者もここまで事を大きくした甲斐があるというものではないか？","ENG":"That way, it'll be more rewarding for the Administrator for causing all this mess.","TWN":"只有這樣，管理者那傢伙把事情鬧大到這種地步才有意義，不是嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자아, 그럼 모처럼이기도 하니……","JPN":"さあ、せっかくじゃ……","ENG":"Now, since it's a special occasion...","TWN":"好了，既然難得遇到了……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"한 손으로 상대해 주지.","JPN":"片手だけで相手してやろうかのう。","ENG":"I shall only use one hand.","TWN":"我讓你一隻手吧。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};